// Utility function to submit API to backend
export const submitDeveloperApi = async (submissionData: any): Promise<{ success: boolean; data?: any; error?: string }> => {
  try {
    const data = await unifiedApiService.processApiConfiguration(submissionData, 'default-user-id', '');
    return { success: true, data };
  } catch (error) {
    console.error('Error during submission:', error);
    return {
      success: false,
      error: error instanceof Error ? error.message : 'Unknown error'
    };
  }
};
